import{_ as e,o as l,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Animal Well","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/games/Animal-Well.md","filePath":"outta-space/knowledge/games/Animal-Well.md"}'),o={name:"outta-space/knowledge/games/Animal-Well.md"};function n(i,a,p,s,d,h){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="animal-well" tabindex="-1">Animal Well <a class="header-anchor" href="#animal-well" aria-label="Permalink to &quot;Animal Well&quot;">​</a></h1><h2 id="_1-핵심-플레이-경험" tabindex="-1">1. 핵심 플레이 경험 <a class="header-anchor" href="#_1-핵심-플레이-경험" aria-label="Permalink to &quot;1. 핵심 플레이 경험&quot;">​</a></h2><p>『Animal Well』은 국밥 같은 메트로배니아 퍼즐 게임이다.</p><p>일반적인 메트로배니아가 몬스터와의 전투를 중심에 둔다면, 이 게임은 탐험, 플랫폼, 퍼즐 풀이에 더 집중한다. 할로우 나이트 같은 대형 메트로배니아와 비교하면 볼륨은 작지만, 진엔딩 기준으로 약 10시간 안팎이면 클리어할 수 있어 부담이 적다.</p><p>맵이 작고 모든 구역이 한 화면에 들어가는 바둑판 같은 구성이 취향에 맞았다. 지도를 잘 살펴보면 숨겨진 부분을 대부분 찾을 수 있어, 길 찾기 스트레스가 크지 않았다.</p><h2 id="_2-조작감과-시스템" tabindex="-1">2. 조작감과 시스템 <a class="header-anchor" href="#_2-조작감과-시스템" aria-label="Permalink to &quot;2. 조작감과 시스템&quot;">​</a></h2><p>메트로배니아의 필수 요소인 “특정 기능 해금 후 이전에 못 갔던 곳 다시 가기”가 잘 구현되어 있다.</p><p>각종 장애물의 배치가 직관적으로 짜여 있어, 눈썰미가 좋다면 공략 없이 올클리어도 가능할 정도다. 퍼즐도 장난감을 어떻게 사용해야 하는지 고민하게 만드는 방식이라 재미있었다. 디스크나 방울 지팡이 같은 도구를 물리적으로 활용하는 느낌이 좋았다.</p><p>다만 스위치 버전 기준으로는 조작과 입력 면에서 불편함이 있었다. 피리 불기가 어렵고, 스캔라인을 켜면 화면이 지나치게 커져서 아무것도 안 보이는 문제가 있었다. 패드로 달걀 코드를 입력하는 것도 상당히 번거로웠다.</p><h2 id="_3-스토리와-캐릭터" tabindex="-1">3. 스토리와 캐릭터 <a class="header-anchor" href="#_3-스토리와-캐릭터" aria-label="Permalink to &quot;3. 스토리와 캐릭터&quot;">​</a></h2><p>스토리는 거의 없는 편이다.</p><p>게임의 강점은 서사나 캐릭터가 아니라, 탐험과 퍼즐, 공간 설계에 있다. 그래서 이야기 중심의 게임을 기대하면 아쉬울 수 있다. 애니멀 웰이 무엇을 뜻하는지조차 명확히 설명되지 않는 느낌이라, 세계관에 대한 해석의 여지는 있지만 스토리적 만족감은 크지 않았다.</p><h2 id="_4-그래픽-사운드-연출" tabindex="-1">4. 그래픽, 사운드, 연출 <a class="header-anchor" href="#_4-그래픽-사운드-연출" aria-label="Permalink to &quot;4. 그래픽, 사운드, 연출&quot;">​</a></h2><p>그래픽과 사운드는 취향저격이었다.</p><p>어둡고 신비로운 분위기, 픽셀 아트, 기묘한 동물들의 배치가 게임의 정체성을 잘 만든다. 화면 전체가 하나의 퍼즐 상자처럼 느껴지고, 작은 맵 안에 여러 비밀을 숨겨둔 방식이 좋았다.</p><h2 id="_5-몰입도와-재플레이-가치" tabindex="-1">5. 몰입도와 재플레이 가치 <a class="header-anchor" href="#_5-몰입도와-재플레이-가치" aria-label="Permalink to &quot;5. 몰입도와 재플레이 가치&quot;">​</a></h2><p>진엔딩을 보고 토끼를 모으는 것까지 전부 했지만, 퍼즐 자체에서는 큰 단점을 느끼지 못했다. 토끼 코드 해석이나 특수문자 퍼즐은 조금 어렵고 복잡했지만, 그 외의 구성은 만족스러웠다.</p><p>정가로 사기에는 다소 비싸게 느껴질 수 있지만, 할인할 때 즐기기에는 좋은 게임이다.</p><p>한 줄 평: 작지만 밀도 높은 맵, 좋은 퍼즐, 훌륭한 분위기를 가진 탐험 중심 메트로배니아.</p>',19)])])}const m=e(o,[["render",n]]);export{c as __pageData,m as default};
